#!/usr/bin/env python3
"""Append an Exit gate line to each v1.1 milestone description lacking one."""
import json, subprocess

GATES = {
    10: "Exit gate: Snowflake leg retired with zero live-verification debt — #194/#195 verified against live Snowflake, the #587 scale baseline recorded, #588 clean retirement (no alert noise) — AND PATs live: 1 admin + 1 member PAT minted and exercised against REST + /mcp.",
    11: "Exit gate: observability + secrets + alerting are vendor-neutral and Azure-verified — logs export via OTel to BOTH App Insights and a local OTLP consumer (#524/#589); SecretStore.delete verified on live Key Vault (#372); dry-run covers UC + flat-file (#532); the alerting batch (#386–#389, #416) merged; #488 + #584 pass — with every live check in the week authenticated by a W1 PAT.",
    12: "Exit gate: the Azure exit is deliberate and complete — final live E2E green BEFORE teardown, #590 done (nothing billable remains except by choice), a fresh clone reaches a green local E2E with zero Azure dependencies (#591), and the frontend refactor batch (#197/#199/#204/#229/#236/#237/#326) is merged.",
    13: "Exit gate: schema_drift is demoable end-to-end (author → dry-run → run → banded severity) on flat-file + UC + local SQL; monitor kinds are no longer SQL-only (#520); the monitor-engine follow-ups (#427–#429) are closed; the baseline-persistence shape is documented for W5 anomaly reuse.",
    14: "Exit gate: the anomaly kind produces banded deviation scores on real metric_value history (skip on cold start) and the trend view renders metric_value with threshold bands + baseline overlay; threshold ordering is validated at authoring time (#568); the results/connections UX batch (#345/#283/#351/#424/#349) is merged.",
    15: "Exit gate: a deliberately oversized local file / UC table runs under the memory cap with sampled-ness recorded on the result (measured against the #587 pushdown baseline); the perf batch (#327/#323) and hardening/small-bug batch (#563/#573/#278/#322/#571/#541/#306) are green; the G-d design doc (#596) + audit ADR (#310) are merged with next-cycle phase-1 issues filed; retro written and v1.1.0 tagged.",
    16: "Exit gate (soft — stretch): every remaining item is either closed or explicitly rolled to v1.2 with a rationale note at the retro. Nothing is silently dropped.",
}

def run(args, inp=None):
    return subprocess.run(args, capture_output=True, text=True, input=inp)

for num, gate in GATES.items():
    r = run(["gh", "api", f"repos/TheurgicDuke771/DataQ/milestones/{num}"])
    m = json.loads(r.stdout)
    desc = m.get("description") or ""
    if "exit gate" in desc.lower():
        print(f"ms{num}: already has a gate — skipped"); continue
    payload = json.dumps({"description": desc + "\n\n" + gate})
    r2 = run(["gh", "api", "-X", "PATCH", f"repos/TheurgicDuke771/DataQ/milestones/{num}", "--input", "-"], inp=payload)
    print(f"ms{num}: {'gate added' if r2.returncode == 0 else 'FAILED ' + r2.stderr[:80]}")
